import{_ as e,o as a,c as n,ag as o}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Normalisation","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/normalisation.md","filePath":"theory/databases/normalisation.md"}'),r={name:"theory/databases/normalisation.md"};function s(d,t,l,i,p,c){return a(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="normalisation" tabindex="-1">Normalisation <a class="header-anchor" href="#normalisation" aria-label="Permalink to &quot;Normalisation&quot;">​</a></h1><p>A poorly designed database is a source of pain: duplicate data takes extra space and leads to inconsistency when you update one record but forget another. <strong>Normalisation</strong> is the systematic process of structuring a database to reduce redundancy and improve data integrity.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 12</p><p>Normalisation to 3NF is a Grade 12 topic and appears in almost every Paper 2 examination. You need to identify problems in a given table and demonstrate how to fix them.</p></div><hr><h2 id="why-normalise" tabindex="-1">Why Normalise? <a class="header-anchor" href="#why-normalise" aria-label="Permalink to &quot;Why Normalise?&quot;">​</a></h2><p>Consider this un-normalised table of student marks:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>StudentID | StudentName | Subject1 | Mark1 | Subject2 | Mark2 | Teacher | TeacherEmail</span></span>
<span class="line"><span>1001      | Alice Adams | IT       | 87    | Maths    | 92    | Smith   | smith@school.co.za</span></span>
<span class="line"><span>1002      | Bob Botha   | IT       | 65    | Maths    | 71    | Smith   | smith@school.co.za</span></span>
<span class="line"><span>1003      | Carol Cole  | IT       | 78    | NULL     | NULL  | Smith   | smith@school.co.za</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>Problems:</strong></p><ul><li><code>Teacher</code> and <code>TeacherEmail</code> repeated for every student → update anomaly (change one, forget another)</li><li><code>Subject1</code>, <code>Mark1</code>, <code>Subject2</code>, <code>Mark2</code> in columns → can&#39;t add a third subject without redesigning</li><li><code>NULL</code> values where Carol has no second subject</li></ul><p>Normalisation fixes all of these.</p><hr><h2 id="the-normal-forms" tabindex="-1">The Normal Forms <a class="header-anchor" href="#the-normal-forms" aria-label="Permalink to &quot;The Normal Forms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Normal Form</th><th>Requirement</th></tr></thead><tbody><tr><td><strong>1NF</strong></td><td>Atomic values; no repeating groups; primary key defined</td></tr><tr><td><strong>2NF</strong></td><td>1NF + no partial dependencies (all non-key fields depend on the WHOLE PK)</td></tr><tr><td><strong>3NF</strong></td><td>2NF + no transitive dependencies (non-key fields depend only on the PK, not on each other)</td></tr></tbody></table><hr><h2 id="first-normal-form-1nf" tabindex="-1">First Normal Form (1NF) <a class="header-anchor" href="#first-normal-form-1nf" aria-label="Permalink to &quot;First Normal Form (1NF)&quot;">​</a></h2><p><strong>Rule:</strong> A table is in 1NF if:</p><ol><li>All values are <strong>atomic</strong> (single value per cell — no lists or multiple values)</li><li>There are <strong>no repeating groups</strong> (no Subject1, Subject2, Subject3 column patterns)</li><li>A <strong>primary key</strong> is defined</li></ol><h3 id="problem-example" tabindex="-1">Problem Example <a class="header-anchor" href="#problem-example" aria-label="Permalink to &quot;Problem Example&quot;">​</a></h3><p><strong>Not in 1NF:</strong></p><table tabindex="0"><thead><tr><th>StudentID</th><th>Name</th><th>Subjects (list)</th></tr></thead><tbody><tr><td>1001</td><td>Alice</td><td>IT, Maths</td></tr><tr><td>1002</td><td>Bob</td><td>Maths</td></tr></tbody></table><p>Problems: <code>Subjects</code> contains multiple values (not atomic); there are implied repeating groups.</p><p><strong>Fixed to 1NF:</strong></p><table tabindex="0"><thead><tr><th>StudentID</th><th>Name</th><th>Subject</th></tr></thead><tbody><tr><td>1001</td><td>Alice</td><td>IT</td></tr><tr><td>1001</td><td>Alice</td><td>Maths</td></tr><tr><td>1002</td><td>Bob</td><td>Maths</td></tr></tbody></table><p>Now <code>(StudentID, Subject)</code> forms a composite primary key.</p><p>But we still have a problem: <code>Name</code> repeats for every subject Alice takes → leads to 2NF issue.</p><hr><h2 id="second-normal-form-2nf" tabindex="-1">Second Normal Form (2NF) <a class="header-anchor" href="#second-normal-form-2nf" aria-label="Permalink to &quot;Second Normal Form (2NF)&quot;">​</a></h2><p><strong>Rule:</strong> A table is in 2NF if:</p><ol><li>It is in 1NF, AND</li><li>Every non-key attribute depends on the <strong>entire</strong> primary key (no partial dependency)</li></ol><p>A <strong>partial dependency</strong> occurs when a non-key column depends on only PART of a composite primary key.</p><h3 id="problem-example-1" tabindex="-1">Problem Example <a class="header-anchor" href="#problem-example-1" aria-label="Permalink to &quot;Problem Example&quot;">​</a></h3><p><strong>In 1NF but NOT 2NF:</strong></p><p>Table: <code>StudentSubjects</code> — PK is <code>(StudentID, SubjectID)</code></p><table tabindex="0"><thead><tr><th>StudentID</th><th>SubjectID</th><th>StudentName</th><th>SubjectName</th><th>Mark</th></tr></thead><tbody><tr><td>1001</td><td>S01</td><td>Alice</td><td>IT</td><td>87</td></tr><tr><td>1001</td><td>S02</td><td>Alice</td><td>Maths</td><td>92</td></tr><tr><td>1002</td><td>S01</td><td>Bob</td><td>IT</td><td>65</td></tr></tbody></table><p><strong>Partial dependencies:</strong></p><ul><li><code>StudentName</code> depends on <code>StudentID</code> alone (not the whole PK)</li><li><code>SubjectName</code> depends on <code>SubjectID</code> alone (not the whole PK)</li><li>Only <code>Mark</code> depends on the full <code>(StudentID, SubjectID)</code> combination</li></ul><p><strong>Fixed to 2NF:</strong> Split into three tables:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Students (StudentID PK, StudentName)</span></span>
<span class="line"><span>Subjects (SubjectID PK, SubjectName)</span></span>
<span class="line"><span>Marks    (StudentID FK, SubjectID FK, Mark)</span></span>
<span class="line"><span>         ← PK: (StudentID, SubjectID)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Now every non-key field in each table depends on the WHOLE primary key.</p><hr><h2 id="third-normal-form-3nf" tabindex="-1">Third Normal Form (3NF) <a class="header-anchor" href="#third-normal-form-3nf" aria-label="Permalink to &quot;Third Normal Form (3NF)&quot;">​</a></h2><p><strong>Rule:</strong> A table is in 3NF if:</p><ol><li>It is in 2NF, AND</li><li>There are <strong>no transitive dependencies</strong> — non-key columns do not depend on other non-key columns</li></ol><p>A <strong>transitive dependency</strong> occurs when: <strong>Non-key A → Non-key B</strong> (B depends on A, not directly on the PK).</p><h3 id="problem-example-2" tabindex="-1">Problem Example <a class="header-anchor" href="#problem-example-2" aria-label="Permalink to &quot;Problem Example&quot;">​</a></h3><p><strong>In 2NF but NOT 3NF:</strong></p><table tabindex="0"><thead><tr><th>StudentID</th><th>Name</th><th>PostalCode</th><th>City</th><th>Province</th></tr></thead><tbody><tr><td>1001</td><td>Alice</td><td>7700</td><td>Stellenbosch</td><td>Western Cape</td></tr><tr><td>1002</td><td>Bob</td><td>7700</td><td>Stellenbosch</td><td>Western Cape</td></tr><tr><td>1003</td><td>Carol</td><td>8000</td><td>Cape Town</td><td>Western Cape</td></tr></tbody></table><p>PK = <code>StudentID</code></p><p><strong>Transitive dependency:</strong></p><ul><li><code>StudentID → PostalCode</code> (PostalCode depends on PK ✓)</li><li>BUT <code>PostalCode → City → Province</code> (City and Province depend on PostalCode, not the PK directly ✗)</li></ul><p>If Stellenbosch&#39;s postal code changes, you must update multiple rows.</p><p><strong>Fixed to 3NF:</strong> Split:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Students  (StudentID PK, Name, PostalCode FK)</span></span>
<span class="line"><span>PostCodes (PostalCode PK, City, Province)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><hr><h2 id="full-normalisation-example" tabindex="-1">Full Normalisation Example <a class="header-anchor" href="#full-normalisation-example" aria-label="Permalink to &quot;Full Normalisation Example&quot;">​</a></h2><p><strong>Start: Un-normalised</strong></p><table tabindex="0"><thead><tr><th>OrderID</th><th>CustomerName</th><th>CustomerEmail</th><th>ProductID</th><th>ProductName</th><th>UnitPrice</th><th>Quantity</th><th>Total</th></tr></thead><tbody><tr><td>1</td><td>Alice</td><td><a href="mailto:alice@mail.com" target="_blank" rel="noreferrer">alice@mail.com</a></td><td>P01</td><td>Laptop</td><td>12000</td><td>2</td><td>24000</td></tr><tr><td>2</td><td>Bob</td><td><a href="mailto:bob@mail.com" target="_blank" rel="noreferrer">bob@mail.com</a></td><td>P02</td><td>Mouse</td><td>200</td><td>5</td><td>1000</td></tr><tr><td>3</td><td>Alice</td><td><a href="mailto:alice@mail.com" target="_blank" rel="noreferrer">alice@mail.com</a></td><td>P01</td><td>Laptop</td><td>12000</td><td>1</td><td>12000</td></tr></tbody></table><p><strong>Problems:</strong></p><ul><li>CustomerName and Email repeat</li><li>ProductName and UnitPrice repeat</li><li>Total is calculated (derived) — unnecessary to store</li><li>No repeating groups in rows, but data is not separated by entity</li></ul><hr><p><strong>After 1NF</strong> — already in 1NF (all cells atomic, one value per cell). PK could be <code>(OrderID, ProductID)</code>.</p><p><strong>After 2NF</strong> — remove partial dependencies:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customers (CustomerID PK, CustomerName, CustomerEmail)</span></span>
<span class="line"><span>Products  (ProductID PK, ProductName, UnitPrice)</span></span>
<span class="line"><span>Orders    (OrderID PK, CustomerID FK, OrderDate)</span></span>
<span class="line"><span>OrderLines(OrderID FK, ProductID FK, Quantity)</span></span>
<span class="line"><span>           PK: (OrderID, ProductID)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>After 3NF</strong> — check for transitive dependencies. In the 2NF version above, all non-key fields depend directly on their table&#39;s PK. We&#39;re in 3NF.</p><hr><h2 id="identifying-normal-form-problems-—-exam-strategy" tabindex="-1">Identifying Normal Form Problems — Exam Strategy <a class="header-anchor" href="#identifying-normal-form-problems-—-exam-strategy" aria-label="Permalink to &quot;Identifying Normal Form Problems — Exam Strategy&quot;">​</a></h2><p>When given a table and asked to identify problems:</p><ol><li><strong>Check 1NF</strong>: Any multi-value cells? Any repeating column groups (Name1, Name2, Name3)?</li><li><strong>Check 2NF</strong>: Is the PK composite? If yes, does any non-key column depend on only PART of the PK?</li><li><strong>Check 3NF</strong>: Does any non-key column depend on another non-key column (not directly on the PK)?</li></ol><p>When asked to convert to a normal form:</p><ul><li><strong>To fix 1NF</strong>: Remove multi-value columns; create a new row for each value</li><li><strong>To fix 2NF</strong>: Split the table; move partially-dependent fields to a new table with their determinant as PK</li><li><strong>To fix 3NF</strong>: Split the table; move transitively-dependent fields to a new table with their determinant as PK</li></ul><hr><h2 id="anomalies-why-normalise" tabindex="-1">Anomalies (Why Normalise?) <a class="header-anchor" href="#anomalies-why-normalise" aria-label="Permalink to &quot;Anomalies (Why Normalise?)&quot;">​</a></h2><p>Un-normalised tables cause three types of anomalies:</p><table tabindex="0"><thead><tr><th>Anomaly</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Update anomaly</strong></td><td>Changing data requires updating multiple rows</td><td>Teacher changes email → must update every student row</td></tr><tr><td><strong>Insertion anomaly</strong></td><td>Can&#39;t insert new data without unrelated data</td><td>Can&#39;t add a new subject unless a student is enrolled</td></tr><tr><td><strong>Deletion anomaly</strong></td><td>Deleting one piece of data deletes unrelated data</td><td>Deleting a student&#39;s record also loses teacher info</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Normalisation</strong></td><td>Process of structuring a database to reduce redundancy</td></tr><tr><td><strong>Normal form</strong></td><td>A level of normalisation with specific rules</td></tr><tr><td><strong>1NF</strong></td><td>Atomic values, no repeating groups, primary key defined</td></tr><tr><td><strong>2NF</strong></td><td>1NF + no partial dependencies</td></tr><tr><td><strong>3NF</strong></td><td>2NF + no transitive dependencies</td></tr><tr><td><strong>Redundancy</strong></td><td>Storing the same data in multiple places</td></tr><tr><td><strong>Partial dependency</strong></td><td>Non-key field depends on part of a composite PK</td></tr><tr><td><strong>Transitive dependency</strong></td><td>Non-key field depends on another non-key field</td></tr><tr><td><strong>Update anomaly</strong></td><td>Inconsistency caused by updating data in only some rows</td></tr><tr><td><strong>Insertion anomaly</strong></td><td>Unable to insert data without adding unrelated data</td></tr><tr><td><strong>Deletion anomaly</strong></td><td>Deleting one record accidentally removes other data</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Identify TWO problems with this table design&quot;</strong> — look for repeating groups, repeated data (redundancy), partial dependencies, transitive dependencies</p></li><li><p><strong>&quot;The table is not in 2NF. Explain why and show the tables in 2NF&quot;</strong> — must identify the partial dependency and demonstrate the split</p></li><li><p><strong>&quot;Explain what a transitive dependency is. Give an example.&quot;</strong> — non-key column depending on another non-key column; example: PostalCode → City (city depends on postal code, not directly on StudentID)</p></li><li><p><strong>&quot;What is a update anomaly? How does normalisation solve it?&quot;</strong> — having to update the same data in multiple rows; normalisation stores data once (in its own table), so one update is sufficient</p></li><li><p><strong>&quot;Convert this table to 3NF. Show all tables with their primary keys and foreign keys.&quot;</strong> — show the final structure: each entity in its own table, PKs and FKs clearly indicated</p></li></ol></div>`,80)])])}const u=e(r,[["render",s]]);export{m as __pageData,u as default};
